def test_create_api_key(auth_client):
    resp = auth_client.post("/auth/api-keys", json={"name": "my-key"})
    assert resp.status_code == 201
    data = resp.json()
    assert "key" in data
    assert data["name"] == "my-key"
    assert len(data["key"]) > 0


def test_create_api_key_requires_auth(client):
    resp = client.post("/auth/api-keys", json={"name": "my-key"})
    assert resp.status_code == 401


def test_list_api_keys(auth_client):
    auth_client.post("/auth/api-keys", json={"name": "key-1"})
    auth_client.post("/auth/api-keys", json={"name": "key-2"})
    resp = auth_client.get("/auth/api-keys")
    assert resp.status_code == 200
    keys = resp.json()
    assert len(keys) == 2
    for k in keys:
        assert "key" not in k
        assert "name" in k


def test_delete_api_key(auth_client):
    resp = auth_client.post("/auth/api-keys", json={"name": "to-delete"})
    key_id = resp.json()["id"]
    resp = auth_client.delete(f"/auth/api-keys/{key_id}")
    assert resp.status_code == 204
    resp = auth_client.get("/auth/api-keys")
    assert all(k["id"] != key_id for k in resp.json())


def test_delete_nonexistent_api_key(auth_client):
    resp = auth_client.delete("/auth/api-keys/99999")
    assert resp.status_code == 404


def test_api_key_updates_last_used(client, api_key):
    client.cookies.clear()
    client.get("/auth/check", headers={"Authorization": f"Bearer {api_key}"})
    # Re-login to list keys and inspect last_used
    client.post("/auth/login", json={"password": TEST_PASSWORD})
    resp = client.get("/auth/api-keys")
    keys = resp.json()
    assert len(keys) == 1
    assert keys[0]["last_used"] is not None


def test_create_text_transfer(auth_client):
    resp = auth_client.post("/transfers/", json={"type": "text", "content": "hello world"})
    assert resp.status_code == 201
    data = resp.json()
    assert data["type"] == "text"
    assert data["content"] == "hello world"

    resp = auth_client.get("/transfers/")
