def test_multi_user_isolation(client):
    """User A cannot see, download, delete, or rename User B's transfers."""
    _create_user(client._session_factory, TEST_PASSWORD)
    _create_user(client._session_factory, TEST_PASSWORD_B)

    # User A creates transfers
    client.post("/auth/login", json={"password": TEST_PASSWORD})
    resp = client.post("/transfers/", json={"type": "text", "content": "A's secret"})
    text_id = resp.json()["id"]
    resp = client.post(
        "/transfers/upload",
        files={"data": ("a.txt", b"A's file data", "text/plain")},
    )
    file_id = resp.json()["id"]

    # Switch to User B
    client.post("/auth/logout")
    client.post("/auth/login", json={"password": TEST_PASSWORD_B})

    # User B sees nothing
    resp = client.get("/transfers/")
    assert len(resp.json()) == 0

    # User B cannot download, delete, or rename
    assert client.get(f"/transfers/{text_id}/download").status_code == 404
    assert client.get(f"/transfers/{file_id}/download").status_code == 404
    assert client.delete(f"/transfers/{text_id}").status_code == 404
    assert client.patch(f"/transfers/{text_id}", json={"content": "hacked"}).status_code == 404

    # User B cannot batch-delete User A's transfers (silent no-op)
    resp = client.post("/transfers/batch-delete", json={"ids": [text_id, file_id]})
    assert resp.status_code == 204
    client.post("/auth/logout")
    client.post("/auth/login", json={"password": TEST_PASSWORD})
    resp = client.get("/transfers/")
    assert len(resp.json()) == 2


def test_batch_delete(auth_client):
    ids = []
    for i in range(3):
        resp = auth_client.post("/transfers/", json={"type": "text", "content": f"item {i}"})
        ids.append(resp.json()["id"])

    resp = auth_client.post("/transfers/batch-delete", json={"ids": ids[:2]})
    assert resp.status_code == 204

    resp = auth_client.get("/transfers/")
    remaining = resp.json()
    assert len(remaining) == 1
    assert remaining[0]["id"] == ids[2]


def test_batch_download(auth_client):
    auth_client.post("/transfers/upload", files={"data": ("a.txt", b"aaa", "text/plain")})
    auth_client.post("/transfers/upload", files={"data": ("b.txt", b"bbb", "text/plain")})
    resp = auth_client.get("/transfers/")
    ids = [t["id"] for t in resp.json()]

    resp = auth_client.post("/transfers/batch-download", json={"ids": ids})
    assert resp.status_code == 201
    assert resp.headers["content-type"] == "application/zip"

    with zipfile.ZipFile(io.BytesIO(resp.content)) as zf:
        names = sorted(zf.namelist())
        assert names == ["a.txt", "b.txt"]
        assert zf.read("a.txt") == b"aaa"
        assert zf.read("b.txt") == b"bbb"


def test_storage_usage(auth_client):
    resp = auth_client.get("/transfers/usage")
    assert resp.status_code == 200
    assert resp.json()["used"] == 0
    assert resp.json()["limit"] == 1024 * 1024 * 1024

    auth_client.post("/transfers/upload", files={"data": ("f.bin", b"x" * 1000, "application/octet-stream")})

    resp = auth_client.get("/transfers/usage")
    assert resp.json()["used"] == 1000
